import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Target, Plus, Trash2, ChevronLeft, ChevronRight, 
  DollarSign, TrendingDown, Star, X, Loader2, Edit2 
} from 'lucide-react';
import '../styles/Metas.css';

const Metas = () => {
  const [loading, setLoading] = useState(false);
  const [mes, setMes] = useState(new Date().getMonth() + 1);
  const [ano, setAno] = useState(new Date().getFullYear());
  const [categorias, setCategorias] = useState([]);
  const [metasExistentes, setMetasExistentes] = useState([]);
  const [tabAtiva, setTabAtiva] = useState('despesa');
  
  // Estados para Modais
  const [showModalNovo, setShowModalNovo] = useState(false);
  const [showModalEdit, setShowModalEdit] = useState(false);
  
  // Estado para Meta em Edição
  const [metaEditando, setMetaEditando] = useState(null);
  const [novaMetaPessoal, setNovaMetaPessoal] = useState({ nome: '', valor: '' });

  useEffect(() => {
    carregarDados();
  }, [mes, ano]);

  async function carregarDados() {
    setLoading(true);
    try {
      const { data: cats } = await supabase.from('categorias').select('*').order('nome');
      const { data: mtd } = await supabase
        .from('metas')
        .select(`*, categorias(nome, cor, id)`)
        .eq('mes_referencia', mes)
        .eq('ano_referencia', ano);
      
      setCategorias(cats || []);
      setMetasExistentes(mtd || []);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setLoading(false);
    }
  }

  const abrirEdicao = (cat, meta) => {
    setMetaEditando({
      categoria_id: cat.id,
      nome: cat.nome,
      cor: cat.cor,
      valor: meta ? meta.valor_meta : '',
      meta_id: meta ? meta.id : null,
      tipo: cat.tipo
    });
    setShowModalEdit(true);
  };

  const salvarEdicao = async () => {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      
      // 1. Atualizar Cor da Categoria
      await supabase
        .from('categorias')
        .update({ cor: metaEditando.cor })
        .eq('id', metaEditando.categoria_id);

      // 2. Upsert da Meta
      const { error } = await supabase
        .from('metas')
        .upsert({
          user_id: user.id,
          categoria_id: metaEditando.categoria_id,
          valor_meta: parseFloat(metaEditando.valor) || 0,
          tipo_meta: tabAtiva,
          mes_referencia: mes,
          ano_referencia: ano
        }, { onConflict: 'categoria_id, mes_referencia, ano_referencia' });

      if (error) throw error;
      
      setShowModalEdit(false);
      carregarDados();
    } catch (error) {
      alert("Erro ao atualizar: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  const criarMetaPessoalCompleta = async () => {
    if (!novaMetaPessoal.nome || !novaMetaPessoal.valor) return;
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();

      const { data: newCat, error: catError } = await supabase
        .from('categorias')
        .insert({ 
          nome: novaMetaPessoal.nome, 
          tipo: 'despesa', 
          cor: '#8b5cf6',
          user_id: user.id 
        })
        .select().single();

      if (catError) throw catError;

      await supabase.from('metas').insert({
        user_id: user.id,
        categoria_id: newCat.id,
        valor_meta: parseFloat(novaMetaPessoal.valor),
        tipo_meta: 'pessoal',
        mes_referencia: mes,
        ano_referencia: ano,
        nome_meta_pessoal: novaMetaPessoal.nome
      });

      setNovaMetaPessoal({ nome: '', valor: '' });
      setShowModalNovo(false);
      carregarDados();
    } catch (error) {
      alert("Erro: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  const deletarMeta = async (id) => {
    if (window.confirm("Deseja excluir este planejamento?")) {
      await supabase.from('metas').delete().eq('id', id);
      setShowModalEdit(false);
      carregarDados();
    }
  };

  return (
    <div className="metas-container fade-in">
      <header className="metas-header">
        <div className="titulo-secao">
          <Target size={28} color="#4361ee" />
          <h1>Metas Financeiras</h1>
        </div>
        
        <div className="seletor-periodo">
          <button onClick={() => setMes(m => m === 1 ? 12 : m - 1)}><ChevronLeft size={20}/></button>
          <span>{new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date(ano, mes - 1))} {ano}</span>
          <button onClick={() => setMes(m => m === 12 ? 1 : m + 1)}><ChevronRight size={20}/></button>
        </div>
      </header>

      <nav className="metas-tabs">
        <button className={tabAtiva === 'despesa' ? 'active' : ''} onClick={() => setTabAtiva('despesa')}>
          <TrendingDown size={18} /> Gastos
        </button>
        <button className={tabAtiva === 'provento' ? 'active' : ''} onClick={() => setTabAtiva('provento')}>
          <DollarSign size={18} /> Receitas
        </button>
        <button className={tabAtiva === 'pessoal' ? 'active' : ''} onClick={() => setTabAtiva('pessoal')}>
          <Star size={18} /> Objetivos
        </button>
      </nav>

      <div className="metas-content">
        {loading && <div className="loading-state"><Loader2 className="spinner" /></div>}
        
        {!loading && (
          <div className={tabAtiva === 'pessoal' ? "metas-pessoais-list" : "grid-metas-cats"}>
            {(tabAtiva === 'pessoal' 
              ? metasExistentes.filter(m => m.tipo_meta === 'pessoal')
              : categorias.filter(c => c.tipo === tabAtiva)
            ).map(item => {
              const meta = tabAtiva === 'pessoal' ? item : metasExistentes.find(m => m.categoria_id === item.id);
              const cat = tabAtiva === 'pessoal' ? item.categorias : item;

              return (
                <div key={item.id} className={tabAtiva === 'pessoal' ? "item-pessoal" : "input-meta-group"} onClick={() => abrirEdicao(cat, meta)}>
                  <div className="info-cat">
                    <div className="dot" style={{backgroundColor: cat?.cor || '#ddd'}}></div>
                    <label>{cat?.nome || item.nome_meta_pessoal}</label>
                  </div>
                  <div className="valor-exibicao">
                    <strong>R$ {Number(meta?.valor_meta || 0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}</strong>
                    <Edit2 size={14} className="edit-icon-hover" />
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {tabAtiva === 'pessoal' && (
        <button className="cat-fab" onClick={() => setShowModalNovo(true)}>
          <Plus size={28} />
        </button>
      )}

      {/* MODAL NOVO OBJETIVO */}
      {showModalNovo && (
        <div className="modal-overlay" onClick={() => setShowModalNovo(false)}>
          <div className="cat-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>Novo Objetivo</h3>
              <button onClick={() => setShowModalNovo(false)}><X size={20} /></button>
            </div>
            <div className="cat-modal-form">
                <input placeholder="Nome" value={novaMetaPessoal.nome} onChange={e => setNovaMetaPessoal({...novaMetaPessoal, nome: e.target.value})} />
                <input type="number" placeholder="Valor" value={novaMetaPessoal.valor} onChange={e => setNovaMetaPessoal({...novaMetaPessoal, valor: e.target.value})} />
                <button className="btn-cat-save" onClick={criarMetaPessoalCompleta}>Criar</button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL EDIÇÃO */}
      {showModalEdit && metaEditando && (
        <div className="modal-overlay" onClick={() => setShowModalEdit(false)}>
          <div className="cat-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>Editar Meta: {metaEditando.nome}</h3>
              <button onClick={() => setShowModalEdit(false)}><X size={20} /></button>
            </div>
            <div className="cat-modal-form">
              <div className="cat-input-box">
                <label>Cor da Categoria</label>
                <input type="color" value={metaEditando.cor} onChange={e => setMetaEditando({...metaEditando, cor: e.target.value})} className="color-picker-mini" />
              </div>
              <div className="cat-input-box">
                <label>Valor da Meta</label>
                <div className="cat-money-input-wrapper">
                  <span className="prefix">R$</span>
                  <input type="number" value={metaEditando.valor} onChange={e => setMetaEditando({...metaEditando, valor: e.target.value})} />
                </div>
              </div>
              <div className="cat-modal-actions">
                <button className="btn-cat-save" onClick={salvarEdicao}>Salvar Alterações</button>
                {metaEditando.meta_id && (
                  <button className="btn-cat-delete" onClick={() => deletarMeta(metaEditando.meta_id)}>
                    <Trash2 size={20} />
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Metas;
